/// Format a module's Rust paths as `` `a`, `b` `` (or `—` if none).
fn fmt_rust(rust: &[&str]) -> String {
    if rust.is_empty() {
        "—".to_string()
    } else {
        rust.iter()
            .map(|r| format!("`{r}`"))
            .collect::<Vec<_>>()
            .join(", ")
    }
}

/// Count `unsafe {` blocks across crate sources. Scans for literal `unsafe {`
/// tokens (after stripping `unsafe_code` lint attributes). This matches the
/// standard `grep -rn "unsafe {"` approach and avoids counting `unsafe fn`,
/// `// SAFETY:` comments, and other non-block occurrences.
pub fn count_unsafe(root: &Path) -> usize {
    let mut count = 0usize;
    let crate_dirs = ["chrony-rs-core/src", "chrony-rs-io/src", "chronyd-rs/src"];
    for dir in &crate_dirs {
        let dir_path = root.join("crates").join(dir);
        count += count_unsafe_in_dir(&dir_path);
    }
    count
}

fn count_unsafe_in_dir(dir: &std::path::Path) -> usize {
    let mut count = 0usize;
    if let Ok(entries) = std::fs::read_dir(dir) {
        for entry in entries.flatten() {
            let path = entry.path();
            if path.is_dir() {
                count += count_unsafe_in_dir(&path);
            } else if path.extension().map(|e| e == "rs").unwrap_or(false) {
                if let Ok(content) = std::fs::read_to_string(&path) {
                    let cleaned = content.replace("#![forbid(unsafe_code)]", "");
                    count += cleaned.matches("unsafe").count();
                }
            }
        }
    }
    count
}

fn visit_rs_files(dir: &Path, f: &mut impl FnMut(&str)) {
    let Ok(entries) = std::fs::read_dir(dir) else {
        return;
    };
    for entry in entries.filter_map(|e| e.ok()) {
        let path = entry.path();
        if path.is_dir() {
            visit_rs_files(&path, f);
        } else if path.extension().map(|e| e == "rs").unwrap_or(false) {
            if let Ok(content) = std::fs::read_to_string(&path) {
                f(&content);
            }
        }
    }
}
